let body = $json.body ?? $json;

// Si llega como text/plain, puede venir string
if (typeof body === "string") {
  try { body = JSON.parse(body); }
  catch { body = {}; }
}

const mensaje = (body.mensaje || body.message || body.text || "").toString().trim();
const history = Array.isArray(body.history) ? body.history : [];
const canal_reserva = (body.canal_reserva || "asistente_ia").toString();

return [{
  json: { mensaje, history, canal_reserva }
}];

let data = $json;

// Si llega como string, intentar parsear
if (typeof data === "string") {
  try {
    data = JSON.parse(data);
  } catch (e) {
    throw new Error("Salida IA inválida: no se pudo parsear JSON");
  }
}

const norm = (s = "") =>
  s
    .toString()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim();

const onlyDigits = (s = "") => s.toString().replace(/\D/g, "");
const cleanEmail = (s = "") => s.toString().trim().toLowerCase();

// Servicios desde el nodo real
const servicios = $items("Traer servicios activos").map(i => i.json);

// Alias
const aliases = {
  "manicura": "manicure",
  "manicuria": "manicure",
  "manicure": "manicure",
  "uñas": "manicure",
  "unas": "manicure",

  "coloracion": "coloración",
  "coloración": "coloración",
  "tintura": "coloración",
  "tinte": "coloración",
  "color": "coloración",

  "corte": "corte",
  "corte de pelo": "corte",
  "corte de cabello": "corte",
  "pelo": "corte",
  "cabello": "corte",

  "maquillaje": "maquillaje",
  "makeup": "maquillaje",
  "make up": "maquillaje"
};

function resolverServicio(servicioNombre = "") {
  const entradaNorm = norm(servicioNombre);
  if (!entradaNorm) return null;

  const canon = aliases[entradaNorm] || entradaNorm;

  let match = servicios.find(s => {
    const nombreNorm = norm(s.nombre || "");
    return nombreNorm === canon || nombreNorm === entradaNorm;
  });

  if (!match) {
    match = servicios.find(s => {
      const nombreNorm = norm(s.nombre || "");
      return nombreNorm.includes(canon) || canon.includes(nombreNorm);
    });
  }

  return match || null;
}

// NUEVO: detectar múltiples servicios en el mismo mensaje / salida
function detectarServiciosMultiples(texto = "") {
  const t = norm(texto);
  if (!t) return [];

  const encontrados = [];

  for (const servicio of servicios) {
    const nombreServicio = norm(servicio.nombre || "");
    if (!nombreServicio) continue;

    // alias asociados a este servicio
    const aliasesDelServicio = Object.entries(aliases)
      .filter(([, valorCanonico]) => norm(valorCanonico) === nombreServicio)
      .map(([alias]) => norm(alias));

    const variantes = [...new Set([nombreServicio, ...aliasesDelServicio])];

    const coincide = variantes.some(v => {
      if (!v) return false;
      return t.includes(v);
    });

    if (coincide) {
      encontrados.push({
        id: servicio.id,
        nombre: servicio.nombre
      });
    }
  }

  // por si el modelo devolvió "corte y maquillaje", etc.
  const unicos = [];
  const vistos = new Set();

  for (const s of encontrados) {
    const clave = `${s.id}|${s.nombre}`;
    if (!vistos.has(clave)) {
      vistos.add(clave);
      unicos.push(s);
    }
  }

  return unicos;
}

function validarHorario(fecha = "", hora = "") {
  if (!fecha || !hora) {
    return { ok: true, motivo: "" };
  }

  const horaOk = /^([01]\d|2[0-3]):(00|30)$/.test(hora);
  if (!horaOk) {
    return {
      ok: false,
      motivo: "Los turnos solo están disponibles en bloques de 30 minutos."
    };
  }

  const fechaBase = new Date(`${fecha}T12:00:00-03:00`);
  if (Number.isNaN(fechaBase.getTime())) {
    return {
      ok: false,
      motivo: "La fecha ingresada no es válida."
    };
  }

  const day = fechaBase.getDay();
  const [hh, mm] = hora.split(":").map(Number);
  const minutes = hh * 60 + mm;

  if (day === 0) {
    return {
      ok: false,
      motivo: "El salón no abre los domingos."
    };
  }

  if (day >= 1 && day <= 5) {
    if (minutes < 540 || minutes > 1200) {
      return {
        ok: false,
        motivo: "Atendemos de lunes a viernes de 09:00 a 20:00."
      };
    }
  }

  if (day === 6) {
    if (minutes < 540 || minutes > 1020) {
      return {
        ok: false,
        motivo: "Los sábados atendemos de 09:00 a 17:00."
      };
    }
  }

  const now = new Date();
  const fechaElegida = new Date(`${fecha}T00:00:00-03:00`);

  const esHoy =
    fechaElegida.getFullYear() === now.getFullYear() &&
    fechaElegida.getMonth() === now.getMonth() &&
    fechaElegida.getDate() === now.getDate();

  if (esHoy) {
    const ahoraConMargen = new Date(now.getTime() + 15 * 60 * 1000);
    const minutosActuales = ahoraConMargen.getHours() * 60 + ahoraConMargen.getMinutes();

    if (minutes <= minutosActuales) {
      return {
        ok: false,
        motivo: "Ese horario ya pasó o está muy próximo. Elegí uno posterior."
      };
    }
  }

  return { ok: true, motivo: "" };
}

// Normalización base
data.intencion = (data.intencion || "").toString().trim().toLowerCase();
data.nombre_cliente = (data.nombre_cliente || "").toString().trim();
data.telefono = onlyDigits(data.telefono || "");
data.email = cleanEmail(data.email || "");
data.fecha = (data.fecha || "").toString().trim();
data.hora = (data.hora || "").toString().trim();
data.notas = (data.notas || "").toString().trim();
data.pregunta = (data.pregunta || "").toString().trim();

// Servicio
const servicioEntrada = data.servicio_nombre || data.servicio || "";
const serviciosDetectados = detectarServiciosMultiples(servicioEntrada);

// NUEVO: si detecta múltiples servicios, frenar acá
if (data.intencion === "reservar" && serviciosDetectados.length > 1) {
  data.servicio_nombre = "";
  data.servicio_id = "";
  data.profesional_id = "";
  data.duracion_minutos = "";

  data.fecha_hora =
    data.fecha && data.hora
      ? `${data.fecha}T${data.hora}:00-03:00`
      : "";

  const faltantes = ["servicio"];
  if (!data.fecha) faltantes.push("fecha");
  if (!data.hora) faltantes.push("hora");
  if (!data.telefono) faltantes.push("telefono");
  if (!data.nombre_cliente) faltantes.push("nombre_cliente");
  if (!data.email) faltantes.push("email");

  data.faltantes = [...new Set(faltantes)];
  data.listo_para_reservar = false;
  data.pregunta = "Por el momento puedo reservar un solo servicio por vez. ¿Cuál querés agendar primero?";

  return [{ json: data }];
}

const servicioMatch = resolverServicio(servicioEntrada);

data.servicio_nombre = servicioMatch?.nombre ?? (servicioEntrada || "");
data.servicio_id = servicioMatch?.id ?? (data.servicio_id || "");
data.profesional_id = servicioMatch?.profesional_id ?? (data.profesional_id || "");
data.duracion_minutos = Number(
  servicioMatch?.duracion_minutos ?? data.duracion_minutos ?? 60
);

// Validar horario
const validacionHorario = validarHorario(data.fecha, data.hora);

if (!validacionHorario.ok) {
  data.hora = "";
  data.pregunta = `${validacionHorario.motivo} Decime un horario válido.`;
}

data.fecha_hora =
  data.fecha && data.hora
    ? `${data.fecha}T${data.hora}:00-03:00`
    : "";

// Faltantes
const faltantes = [];
if (!data.servicio_id) faltantes.push("servicio");
if (!data.fecha) faltantes.push("fecha");
if (!data.hora) faltantes.push("hora");
if (!data.telefono) faltantes.push("telefono");
if (!data.nombre_cliente) faltantes.push("nombre_cliente");
if (!data.email) faltantes.push("email");

// Validación email
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (data.email && !emailRegex.test(data.email)) {
  data.email = "";
  if (!faltantes.includes("email")) faltantes.push("email");
  if (!data.pregunta) {
    data.pregunta = "Necesito un email válido para enviarte el recordatorio del turno.";
  }
}

data.faltantes = faltantes;

data.listo_para_reservar =
  data.intencion === "reservar" &&
  faltantes.length === 0;

if (!data.listo_para_reservar && !data.pregunta && data.intencion === "reservar") {
  const etiquetas = {
    servicio: "el servicio",
    fecha: "la fecha",
    hora: "la hora",
    telefono: "tu teléfono",
    nombre_cliente: "tu nombre",
    email: "tu email"
  };

  const faltantesTexto = faltantes.map(f => etiquetas[f] || f).join(", ");
  data.pregunta = `Para confirmar tu reserva necesito ${faltantesTexto}.`;
}

return [{ json: data }];

const base = (() => {
  try {
    return $node["Normalizar IA"].json || {};
  } catch {
    return {};
  }
})();

const ctx = { ...base, ...$json };

const citaCreada = (() => {
  try {
    return $node["Crear cita"].json || null;
  } catch {
    return null;
  }
})();

const citaExistente = (() => {
  try {
    return $node["Buscar citas en ese horario"].json || null;
  } catch {
    return null;
  }
})();

function formatearFechaHora(iso) {
  if (!iso) return "";
  const d = new Date(iso);
  return d.toLocaleString("es-AR", {
    timeZone: "America/Argentina/Buenos_Aires",
    weekday: "long",
    day: "2-digit",
    month: "long",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false
  });
}

if (ctx.error) {
  return [{
    json: {
      ok: false,
      respuesta: "Hubo un problema al consultar o guardar la reserva. Intentá nuevamente en unos minutos."
    }
  }];
}

if (!ctx.listo_para_reservar) {
  return [{
    json: {
      ok: true,
      respuesta: ctx.pregunta || "Necesito algunos datos más para continuar con la reserva."
    }
  }];
}

if (citaCreada?.id) {
  return [{
    json: {
      ok: true,
      respuesta:
        `Tu reserva ha sido confirmada.\n\n` +
        `📅 Servicio: ${ctx.servicio_nombre}\n` +
        `🗓 Fecha y hora: ${formatearFechaHora(ctx.fecha_hora)}\n` +
        `📍 Salón Bella\n\n` +
        `Recibirás un recordatorio automático antes del turno.`
    }
  }];
}

if (citaExistente?.id && !citaCreada?.id) {
  return [{
    json: {
      ok: false,
      respuesta:
        `Ese horario ya no está disponible para ${ctx.servicio_nombre || "el servicio solicitado"}.\n\n` +
        `Decime otro horario y te ayudo a confirmarlo.`
    }
  }];
}

return [{
  json: {
    ok: false,
    respuesta: "No pude completar la reserva. Intentá nuevamente."
  }
}];

const raw = ($json.output ?? "").toString();
let s = raw.replace(/```json|```/g, "").trim();

let obj;

try {
  obj = JSON.parse(s);
} catch (e) {
  const m = s.match(/\{[\s\S]*\}/);
  if (!m) {
    obj = {
      intencion: "otro",
      nombre_cliente: "",
      telefono: "",
      email: "",
      servicio_nombre: "",
      fecha: "",
      hora: "",
      notas: "",
      faltantes: [],
      pregunta: "No pude interpretar el mensaje. ¿Qué servicio y horario querés reservar?",
      listo_para_reservar: false
    };
  } else {
    obj = JSON.parse(m[0]);
  }
}

const base = (() => {
  try {
    return $node["Unificar entrada + servicios"].json || {};
  } catch {
    return {};
  }
})();

return [{
  json: {
    ...base,
    ...obj
  }
}];

const entrada = $items("Parsear entrada")[0].json;
const servicios = $items("Traer servicios activos").map(i => i.json);

const mensaje = (entrada.mensaje ?? "").toString().trim();
const history = Array.isArray(entrada.history) ? entrada.history : [];
const canal_reserva = (entrada.canal_reserva ?? "asistente_ia").toString();

const hoy_local = new Date().toLocaleDateString("en-CA", {
  timeZone: "America/Argentina/Buenos_Aires"
});

const servicios_compactos = servicios
  .map(s => `${s.id}|${s.nombre}`)
  .join("\n");

const history_text = history
  .slice(-10)
  .map(m => `${(m.role || "user").toUpperCase()}: ${(m.content || "").toString().trim()}`)
  .join("\n");

return [{
  json: {
    ...entrada,
    mensaje,
    history,
    canal_reserva,
    servicios,
    hoy_local,
    servicios_compactos,
    history_text
  }
}];

const base = $node["Normalizar IA"].json || {};
const servicios = $items("Traer servicios activos").map(i => i.json);

const servicio = servicios.find(
  s => String(s.id) === String(base.servicio_id)
);

const profesional_id = base.profesional_id || servicio?.profesional_id || "";

if (!base.fecha_hora || !base.servicio_id || !servicio) {
  return [{
    json: {
      ...base,
      profesional_id,
      duracion_minutos: null,
      fecha_fin: ""
    }
  }];
}

const duracion = Number(servicio.duracion_minutos || 60);
const inicio = new Date(base.fecha_hora);
const fin = new Date(inicio.getTime() + duracion * 60000);

return [{
  json: {
    ...base,
    profesional_id,
    duracion_minutos: duracion,
    fecha_fin: fin.toISOString()
  }
}];
